async function streamPluginBridge(apiBase, apiKey, pluginId, channel, durationMs) {
  const controller = new AbortController();
  const timer = durationMs === void 0 ? null : setTimeout(() => controller.abort(), durationMs);
  try {
    const response = await fetch(buildApiUrl2(
      apiBase,
      `/api/plugins/${encodeURIComponent(pluginId)}/bridge/stream/${encodeURIComponent(channel)}`
    ), {
      headers: apiKey ? { authorization: `Bearer ${apiKey}` } : void 0,
      signal: controller.signal
    });
    if (!response.ok) {
      const text95 = await response.text();
      throw new Error(text95.trim() || `Request failed with status ${response.status}`);
    }
    if (!response.body) return;
    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    while (true) {
      const { value, done } = await reader.read();
      if (done) break;
      if (value) process.stdout.write(decoder.decode(value, { stream: true }));
    }
    const trailing = decoder.decode();
    if (trailing) process.stdout.write(trailing);
  } catch (error) {
    if (error instanceof Error && error.name === "AbortError") return;
    throw error;
  } finally {
    if (timer) clearTimeout(timer);
  }
}
function buildApiUrl2(apiBase, path31) {
  const url = new URL(apiBase);
  url.pathname = `${url.pathname.replace(/\/+$/, "")}${path31.startsWith("/") ? path31 : `/${path31}`}`;
  return url.toString();
}

