async function connectWizard(opts) {
  if (!process.stdin.isTTY || !process.stdout.isTTY) {
    throw new Error("`paperclipai connect` is interactive. For scripts, pass --api-base/--api-key or use context set/token commands.");
  }
  p18.intro(pc34.bgCyan(pc34.black(" paperclipai connect ")));
  const context = readContext(opts.context);
  const resolvedProfile = resolveProfile(context, opts.profile);
  const initialApiBase = resolveApiBase(opts, resolvedProfile.profile);
  const apiBaseInput = await p18.text({
    message: "Paperclip API base",
    initialValue: initialApiBase,
    placeholder: "http://localhost:3100"
  });
  assertNotCancelled(apiBaseInput);
  const apiBase = normalizeApiBase2(String(apiBaseInput || initialApiBase));
  console.log(pc34.dim(`Checking ${apiBase}/api/health ...`));
  await verifyHealth(apiBase);
  const boardLogin = await loginBoardCli({
    apiBase,
    requestedAccess: "board",
    requestedCompanyId: opts.companyId ?? resolvedProfile.profile.companyId ?? null,
    command: "paperclipai connect"
  });
  const boardApi = new PaperclipApiClient({ apiBase, apiKey: boardLogin.token });
  const companies2 = await boardApi.get("/api/companies") ?? [];
  const persona = await choosePersona(opts.persona);
  const profileName = opts.profile?.trim() || await askProfileName(resolvedProfile.name);
  const apiKeyEnvVarName = opts.apiKeyEnvVarName?.trim() || "PAPERCLIP_API_KEY";
  if (persona === "board") {
    const company2 = await chooseCompany(companies2, opts.companyId ?? resolvedProfile.profile.companyId, {
      optional: true
    });
    const tokenName2 = opts.tokenName?.trim() || `cli-board-${(/* @__PURE__ */ new Date()).toISOString()}`;
    const key2 = await boardApi.post("/api/board-api-keys", createBoardApiKeySchema.parse({
      name: tokenName2,
      requestedCompanyId: company2?.id ?? null
    }));
    if (!key2) throw new Error("Failed to create board token");
    upsertProfile(profileName, {
      apiBase,
      companyId: company2?.id,
      persona: "board",
      agentId: "",
      agentName: "",
      apiKeyEnvVarName,
      tokenName: key2.name,
      tokenId: key2.id,
      tokenCreatedAt: key2.createdAt
    }, opts.context);
    setCurrentProfile(profileName, opts.context);
    p18.outro(pc34.green(`Connected profile '${profileName}' as board.`));
    return {
      ok: true,
      profile: profileName,
      persona: "board",
      apiBase,
      companyId: company2?.id ?? null,
      key: publicKeyResult(key2),
      exports: buildExports({ apiBase, companyId: company2?.id, agentId: void 0, envName: apiKeyEnvVarName, token: key2.token })
    };
  }
  const company = await chooseCompany(companies2, opts.companyId ?? resolvedProfile.profile.companyId, {
    optional: false
  });
  if (!company) throw new Error("Company is required for agent profiles");
  const agents2 = await boardApi.get(apiPath`/api/companies/${company.id}/agents`) ?? [];
  if (agents2.length === 0) throw new Error(`Company '${company.name}' has no agents to connect.`);
  const agent = await chooseAgent(agents2, resolvedProfile.profile.agentId);
  const tokenName = opts.tokenName?.trim() || `cli-agent-${(/* @__PURE__ */ new Date()).toISOString()}`;
  const key = await boardApi.post(apiPath`/api/agents/${agent.id}/keys`, createAgentKeySchema.parse({ name: tokenName }));
  if (!key) throw new Error("Failed to create agent token");
  upsertProfile(profileName, {
    apiBase,
    companyId: company.id,
    persona: "agent",
    agentId: agent.id,
    agentName: agent.name,
    apiKeyEnvVarName,
    tokenName: key.name,
    tokenId: key.id,
    tokenCreatedAt: key.createdAt
  }, opts.context);
  setCurrentProfile(profileName, opts.context);
  p18.outro(pc34.green(`Connected profile '${profileName}' as ${agent.name}.`));
  return {
    ok: true,
    profile: profileName,
    persona: "agent",
    apiBase,
    companyId: company.id,
    agentId: agent.id,
    agentName: agent.name,
    key: publicKeyResult(key),
    exports: buildExports({ apiBase, companyId: company.id, agentId: agent.id, envName: apiKeyEnvVarName, token: key.token })
  };
}
