async function resolveAgent2(api, companyId, agentRef) {
  const trimmed = agentRef.trim();
  if (!trimmed) throw new Error("Agent reference is required");
  if (/^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(trimmed)) {
    const agent2 = await api.get(apiPath`/api/agents/${trimmed}`);
    if (!agent2 || agent2.companyId !== companyId) throw new Error(`Agent not found: ${agentRef}`);
    return agent2;
  }
  const query = new URLSearchParams({ companyId });
  const agent = await api.get(`${apiPath`/api/agents/${trimmed}`}?${query.toString()}`);
  if (!agent || agent.companyId !== companyId) throw new Error(`Agent not found: ${agentRef}`);
  return agent;
}
function resolveBoardKeyExpiresAt(opts) {
  if (opts.neverExpires) return null;
  if (opts.expiresAt?.trim()) {
    const date2 = new Date(opts.expiresAt.trim());
    if (!Number.isFinite(date2.getTime())) throw new Error(`Invalid --expires-at value: ${opts.expiresAt}`);
    return date2;
  }
  if (opts.ttlDays?.trim()) {
    const days = Number(opts.ttlDays);
    if (!Number.isFinite(days) || days <= 0) throw new Error(`Invalid --ttl-days value: ${opts.ttlDays}`);
    return new Date(Date.now() + Math.floor(days * 24 * 60 * 60 * 1e3));
  }
  return void 0;
}

